import{_ as p,o as e,c as a,j as r,a as t,a1 as d}from"./chunks/framework.Bp7r_-XI.js";const c=JSON.parse('{"title":"宝可梦技能—格斗","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/7.载具及随从/随从/7.系列随从/宝可梦系列/2.宝可梦技能机器/宝可梦技能—格斗.md","filePath":"4.资源分区/7.物品与装备/7.载具及随从/随从/7.系列随从/宝可梦系列/2.宝可梦技能机器/宝可梦技能—格斗.md"}'),A={name:"4.资源分区/7.物品与装备/7.载具及随从/随从/7.系列随从/宝可梦系列/2.宝可梦技能机器/宝可梦技能—格斗.md"};function n(s,b,B,o,_,l){return e(),a("div",null,[...b[0]||(b[0]=[r("h1",{id:"宝可梦技能—格斗",tabindex:"-1"},[t("宝可梦技能—格斗 "),r("a",{class:"header-anchor",href:"#宝可梦技能—格斗","aria-label":'Permalink to "宝可梦技能—格斗"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：勿忘尘004D")])])],-1),d('<h1 id="宝可梦技能—格斗-1" tabindex="-1">宝可梦技能—格斗 <a class="header-anchor" href="#宝可梦技能—格斗-1" aria-label="Permalink to &quot;宝可梦技能—格斗&quot;">​</a></h1><p>宝可梦技能—格斗<br> 特别说明：格斗系技能中物理系技能造成的伤害均为物理伤害。法伤技能造成的均为力场伤害。<br> 所有格斗系技能皆具不有【法破】特性，需使用其他方式获得命中灵体的能力。<br> 【声明】：具有这一词条的技能是在一个战斗轮开始时决定发动的，除了花费声明动作外，训练家本轮的指挥动作也将在声明后被直接占用并消耗。</p><p>空手劈 C+1000<br> 指挥动作：标准动作。<br> 宝可梦消耗动作：标准动作<br> 效果：格斗系物理技能，该宝可梦进行一次近战攻击检定造成挥砍伤害，本次攻击获得9dp加值，这是技艺加值以及来自技艺的2点附加成功。本次攻击具有【9加骰】【毁灭】特性。<br> 差价升级至B+2000<br> 差价升级后仍可使用技艺的较低级别版本。<br> 则本技能攻击中附带的技艺附加成功提升至4点，【9加骰】提升至【8加骰】，【毁灭】提升至【湮灭】，并获得【接触攻击】特性。</p><p>踢倒 C+1000<br> 指挥动作：标准动作。<br> 宝可梦消耗动作：标准动作<br> 效果：格斗系物理技能，该宝可梦进行一次近战攻击检定造成钝击伤害，本次攻击为瞄准对手用以站立/移动的肢体攻击，不承受通常瞄准肢体部位的减值(但目标若是具有增加部位攻击减值的能力依然正常生效）。本次攻击具有【9加骰】【高速5】特性，本次攻击命中后附带3点不可豁免的肢体妨碍点数（创伤来源）。<br> 差价升级至B+2000<br> 差价升级后仍可使用技艺的较低级别版本。<br> 则本技能攻击中附带的不可豁免的肢体妨碍点数（创伤来源）提升至5点，【9加骰】提升至【8加骰】并获得【接触攻击】特性。</p><p>近身战 C+1000<br> 指挥动作：标准动作。<br> 宝可梦消耗动作：标准动作<br> 效果：格斗系物理技能，该宝可梦进行一次近战攻击检定造成钝击伤害，这次攻击获得11dp技艺加值和3点来自技艺的附加成功，并具有10点高速和5点威猛。使用本技能后，该宝可梦获得等于感知属性一半的士气防御减值和等于敏捷属性一半的基础防御减值(皆向下取整，最低减到0），持续一个场景。<br> 差价升级至B+2000/A+4000<br> 差价升级后仍可使用技艺的较低级别版本。<br> B级效果：本技能攻击中附带的技艺加值提升至宝可梦敏捷属性点，附加成功提升至5，并获得【接触攻击】特性。<br> A级效果：本技能攻击中附带的技艺加值提升至宝可梦敏捷属性点，获得【接触攻击】特性，攻击中附带的附加成功提升至10，获得【长点射】特性。这次攻击忽略对手的格挡防御和闪避防御，这是一个A级幻象来源的效果（拳风密集，宛若凭空多出了十余拳，令对手躲闪不及难以招架）。</p><p>飞膝踢 C+1000<br> 指挥动作：标准动作。<br> 宝可梦消耗动作：标准动作<br> 效果：格斗系物理技能，声明使用本技能后，需先骰一个自然骰D10（无法获得任何能力的加成），若结果为1、2、3，则本次技能使用失败，宝可梦受到等同于生命池上限一半的严重伤害（向下取整）。<br> 若自然骰结果为3以上，则该宝可梦进行一次近战攻击检定造成钝击伤害，本次攻击获得11dp技艺加值以及来自技艺的4点附加成功。本次攻击具有【9加骰】【毁灭】特性。<br> 差价升级至B+2000/A+4000<br> 差价升级后仍可使用技艺的较低级别版本。<br> B级效果：本技能攻击中的技艺加值提升至宝可梦的力量属性点，附带的技艺附加成功提升至7点，【9加骰】提升至【8加骰】，【毁灭】提升至【湮灭】，并获得【接触攻击】特性。<br> A级效果：技能攻击中的技艺加值提升至宝可梦的力量属性点，具有【8加骰】、【湮灭】、【接触攻击】特性。本技能的技艺附加成功提升至12，攻击触及范围提升40米。这次攻击忽略对手的闪避和洞察防御（视为这一击踢击速度极快，仿若一道幻影），这是一个A级幻象来源的效果。</p><p>双倍奉还B+2000<br> 声明动作：自由动作<br> 指挥动作：标准动作<br> 宝可梦消耗动作：标准动作<br> 效果：格斗系物理技能，你必须在一个战斗回合开始之前指定一个目标并发出【声明】你要使用该技能，目标会知晓本技能的实际效果，该宝可梦的先攻轮次降低至本轮最后一位，持续一轮。<br> 在宝可梦的回合开始后，宝可梦需使用双倍奉还攻击指定的目标，这次攻击具有【湮灭】与等同于目标本轮对宝可梦造成伤害值的附加成功，这是技艺加值，因此技艺获得的附加成功不能超过宝可梦耐力属性值。</p><p>地球上投B+2000<br> 指挥动作：标准动作<br> 宝可梦消耗动作：整轮动作+下一轮的标准动作。<br> 描述：宝可梦会携带着目标向天空飞去（跃起），接着在空中环绕并携带目标以惊人的势能向地面俯冲，借助引力与速度给予对手重创<br> 效果：格斗系物理技能，该宝可梦以近战攻击检定对触及范围内的一个目标进行一次擒抱。擒抱检定命中后，目标会立即进入B级创伤来源的定身状态。接着宝可梦会携带目标往天空进行一次移动。在下一轮宝可梦会带着目标俯冲而下，将目标重重的摔在地面上。目标需要进行两次强韧豁免。第一次强韧豁免DC为宝可梦近战攻击检定的成功数+6，失败则受到差值的力场伤害。第二次强韧豁免其从高空坠落所受到的坠落伤害，坠落高度为宝可梦这一轮与上一轮所处于相对地面的最高位置。这之后，目标受到的定身状态解除，并在一场景内飞行机动性下降二级（完美-良好-普通-笨拙），若下降至笨拙以下，则目标无法进行飞行，这是一个B级创伤来源的负面效果。<br> 特殊的，若目标没有进入定身状态，其在自己行动轮内可发起与宝可梦的擒抱对抗，若成功则可脱离地球上投效果影响，其所处的位置与脱离擒抱时宝可梦位置相同。</p><p>音速拳C+1000<br> 声明动作：反射动作<br> 指挥动作：标准动作<br> 宝可梦消耗动作：标准动作<br> 效果：格斗系物理技能，该宝可梦进行一次近战攻击检定造成钝击伤害，本次攻击具有2点来自技艺的附加成功。<br> 使用本技能必须在一个战斗轮开始之前发出【声明】，声明以后将宝可梦的先攻提高18点，持续到本轮结束。本次攻击具有【9加骰】【毁灭】特性。<br> 差价升级至B+2000/A+4000<br> 差价升级后仍可使用技艺的较低级别版本。<br> 提升至B级效果：本次攻击附带的附加成功提升至4点，先攻提升效果提升至36点，【9加骰】提升为【8加骰】，【毁灭】提升至【湮灭】。<br> 提升至A级效果：附加成功提到8点、先攻提升效果提升至72点，具有【接触攻击】、【8加骰】、【湮灭】特性。这次攻击忽略对手的格挡防御，这是一个A级的幻象来源效果（视为这一拳的速度极快，见缝插针）。</p><p>爆裂拳 C+1000<br> 指挥动作：标准动作。<br> 宝可梦消耗动作：标准动作<br> 效果：格斗系物理技能，该宝可梦进行一次近战攻击检定造成钝击伤害，攻击附带等同于宝可梦力量属性点的技艺加值以及1点来自技艺的附加成功。本次攻击命中后使对手陷入混乱状态一轮，随机攻击离它最近的目标，这视为一个C级幻象来源的混乱效果。<br> 差价升级至B+2000/A+4000<br> 差价升级后仍可使用技艺的较低级别版本。<br> B级效果：本技能攻击中附带的技艺附加成功提升至5点，获得【接触攻击】特性。攻击命中后的混乱效果提升为B级幻象来源，处于混乱状态单位的攻击会避开该宝可梦与训练家。<br> A级效果：本技能攻击中附带的技艺附加成功提升至13点，攻击命中后的混乱效果提升为A级幻象来源，即对方的攻击会避开该宝可梦及该宝可梦的队友，只攻击对手的同阵营目标。这次攻击忽略对手的格挡防御，这是一个A级的幻象效果来源（视为一个拳头具有无限放大的幻影，挡无可挡）。</p><p>真气拳C+1000<br> 蓄力技<br> 指挥动作：整轮动作+下一轮的标准动作。<br> 宝可梦消耗动作：整轮动作+下一轮的标准动作<br> 效果：格斗系物理技能，该宝可梦需要先消耗一个整轮动作进行蓄力，蓄力后直到下一轮开始前被称为蓄力过程，蓄力过程中宝可梦与训练家视为进行了全防御，若蓄力过程中受到了超过宝可梦生命值一半的伤害（来自于任意目标的攻击检定伤害，但不包括该宝可梦身上承受的异常点数带来的伤害），则视为该技能被打断无法使用，且照常消耗宝可梦和训练家的下一轮标准动作。<br> 若蓄力过程未被打断，则下一轮该宝可梦可进行一次近战攻击，造成钝击伤害。这次攻击中附带等同于宝可梦力量属性点的技艺加值同时这次攻击具有10威猛，10高速，10破甲。<br> 差价升级至B+2000/A+4000<br> 差价升级后仍可使用技艺的较低级别版本。<br> B级效果：触及距离提升至15米，威猛提升至20，高速提升至20，破甲提升至20并具有【接触攻击】特性。<br> A级效果：这次攻击的触及距离提升至135米，威猛提升至40，高速提升至40，破甲提升至40。这次攻击忽略对手的力场防御（视为这一击凝聚了该宝可梦的精气神，可以借此贯穿对手的物理以外的防御手段），这是一个A级的影响心灵来源的效果。</p><p>真空波C+1000<br> 声明动作：反射动作<br> 指挥动作：标准动作<br> 宝可梦消耗动作：标准动作<br> 效果：格斗系法伤技能，该宝可梦进行一次施法攻击检定造成力场伤害，本次攻击具有1点来自技艺的附加成功，射程60米。使用本次攻击必须在一个战斗轮的开始之前【声明】，声明以后将先攻提高18点，持续到本轮结束。本次攻击具有【9加骰】【毁灭】特性。<br> 差价升级至B+2000/A+4000<br> 差价升级后仍可使用技艺的较低级别版本。<br> 提升至B级效果：本次攻击射程提升至120米，先攻提升效果提升至28点，【9加骰】提升为【8加骰】，【毁灭】提升至【湮灭】。<br> 提升至A级效果：本次攻击射程提升至宝可梦的敏感范围，先攻提升效果提升至64点。这次攻击获得等同宝可梦智力属性点能量加值。忽略对手的闪避防御，这是一个A级的幻象来源效果（视为这一拳的速度极快，对手来不及躲开）。</p><p>蛮力C+1000<br> 指挥动作：标准动作。<br> 宝可梦消耗动作：标准动作<br> 效果：格斗系物理技能，该宝可梦进行一次近战攻击检定造成钝击伤害，这次攻击获得11dp技艺加值和3点来自技艺的附加成功，并具有10点高速和5点威猛。使用本技能后，该宝可梦获得等于力量属性一半的力量检定减值和等于敏捷属性一半的基础防御减值(皆向下取整，最低减到0），持续一个场景。<br> 差价升级至B+2000/A+4000<br> 差价升级后仍可使用技艺的较低级别版本。<br> B级效果：本技能攻击中附带的技艺加值提升至力量属性点，附加成功提升至6，并获得【接触攻击】特性。<br> A级效果：本技能攻击中附带的技艺加值提升至力量属性点，本技能攻击中附带的附加成功提升至10，并获得【长点射】、【接触攻击】特性，这次攻击忽略对手的格挡防御和偏斜防御，这是一个A级幻象来源的效果（宝可梦凝聚全身力量的一击，令对手躲闪不及难以招架）。</p><p>发劲B+2000<br> 指挥动作：标准动作<br> 宝可梦消耗动作：标准动作<br> 效果：格斗系物理技能，该宝可梦进行一次近战攻击检定造成钝击伤害，这次攻击附带6dp技艺加值和2点来自于技艺的附加成功并具有【威猛5】，这次攻击命中后会造成2点不可豁免的麻痹点数（创伤来源）。<br> 差价升级至B+2000<br> 差价升级后仍可使用技艺的较低级别版本。<br> B级效果：攻击附带技艺加值提升至8dp，麻痹点数（创伤来源）提升至4，威猛提升至10，并具有【接触攻击】特性。</p><p>吸取拳C+1000<br> 指挥动作：标准动作<br> 宝可梦消耗动作：标准动作<br> 效果：格斗系物理技能，该宝可梦进行一次近战攻击检定造成钝击伤害，这次攻击附带3点来自于技艺的附加成功并具有【威猛5】【吸血5】。<br> 差价升级至B+2000/A+4000<br> 差价升级后仍可使用技艺的较低级别版本。<br> B级效果：攻击附带的吸血点数提升至10，威猛提升至7，并具有【接触攻击】特性。<br> A级效果：攻击附带的附加成功提升至8点，吸血点数提升至15，威猛提升至15。忽略对手的闪避防御，这是一个A级环境来源的效果（视为这一拳带动了周身的气场，压迫对手的闪躲空间）。</p><p>圣剑A+4000<br> 指挥动作：标准动作。<br> 宝可梦消耗动作：标准动作<br> 效果：格斗系物理技能，该宝可梦进行一次近战攻击检定造成挥砍伤害，本次攻击获得等同于力量属性点的技艺加值，触及范围提升至160米。本次攻击具有【8加骰】【湮灭】【接触攻击】特性并忽略对手的偏斜和力场防御，这是一个A级命运来源的效果（视为宝可梦的手臂延伸出一道光剑劈砍而下，切碎了所有法系防御）。</p><p>波导弹C+1000<br> 指挥动作：标准动作<br> 宝可梦消耗动作：标准动作<br> 效果：格斗系法伤技能，该宝可梦进行一次施法攻击检定，这次攻击检定+9dp的技艺加值和1点来自与技艺的附加成功，射程30米。这次攻击额外具有10破甲和5破魔的特性。<br> 差价升级至B+2000/A+4000<br> 差价升级后仍可使用技艺的较低级别版本。<br> B级效果：这次攻击附带的技艺加值提升至宝可梦施法属性主属性点，附加成功提升至2，射程提升至90米，并获得【能量武器】特性。<br> A级效果：这次攻击附带的技艺加值提升至宝可梦施法属性主属性点，附加成功提升至2，攻击射程提升至敏感范围，具有能量武器特性，破甲、破魔提升至15。这次攻击忽略对手的基础防御和闪避防御，这是一个A级的幻象来源效果（波导弹象征着必中，无法躲开！）。</p><p>健美B+2250<br> 指挥动作：移动动作<br> 宝可梦消耗动作：移动动作<br> 效果：格斗系变化技能，该宝可梦开始锻炼自己，提升等同于自己力量属性值一半的力量增强加值及2点来自技艺的附加成功和等同于自己耐力属性值一半的天生防御及2点基于天生防御的附加成功，持续一个场景。健美对于每个宝可梦一场景最多使用一次。</p><p>快速防守C+1000<br> 指挥动作：迅捷/反射动作<br> 宝可梦消耗动作：移动动作<br> 效果：格斗系变化技能，该宝可梦进行一次格挡，并且15米范围内的友方角色获得对抗范围攻击时获得9dp偏斜防御和2点基于偏斜防御的附加成功。</p><p>看穿B+2000<br> 指挥动作：迅捷动作<br> 宝可梦消耗动作：移动动作<br> 效果：格斗系变化技能，该宝可梦进行一次格挡防御，并额外获得7点闪避防御和4点基于闪避防御的附加成功以及7点洞察防御和4点基于洞察防御的附加成功。</p><p>扑击A+4000<br> 指挥动作：标准动作<br> 宝可梦消耗动作：标准动作<br> 效果：格斗系物理技能，该宝可梦进行一次近战攻击检定，这次攻击获得等同于该宝可梦天生防御的技艺加值并获得4点来自技艺的附加成功。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',23)])])}const h=p(A,[["render",n]]);export{c as __pageData,h as default};
